% showECGonThorax(ECG,leadsys[,signodes])% This script is used to display a BSM of the amsterdam, nijmgen or STW pig BSM ssytem% on a thorax. % ECG: BSM signals [nsig, nsamp].% leadsys: lead system used (nim,ams,pigbsm)% Signodes optionally describes which nodes the BSM corresponds to. % When signodes is not configured default values are used and it is assumed that the first % nodes represent the BSM electrodes% 20120621 oostep1: Set number of electrodes depending on leadsys. Added pigbsm% lead system. Added signodes as optional input.function [VER,ITRI,VALS]=showBSMonThorax(ECG,leadsys,signodes)it=1;if isempty(ECG)    ECG=MeanECG(:,it,:);endif ~exist('leadsys')    leadsys='ams';endif strfind(leadsys,'nim')    [VER,ITRI] = loadNIMGEOM();    sigdef=1:65;elseif strfind(leadsys,'ams')    [VER,ITRI] = loadAMSGEOM();    sigdef=1:65;elseif strfind(leadsys,'pigbsm')    [VER,ITRI] = loadPIGBSM();    sigdef=1:64;else error('Unknown leadsystem: %s',leadsys);endif ~exist('signodes')    signodes=sigdef;endT=intripol(VER,ITRI,signodes);VALS= T*ECG(1:length(signodes),:);if  exist('qtriplot')    a=max(max(max(abs(VALS))));    a=min(a,1.5);    qtriplot('delete *');    qtriplot(VER,ITRI,'thorax');    qtriplot(VALS)    qtriplot('funcolor rainbow');    qtriplot(['funscale ' num2str([-a a])])%     qtriplot(['column ' num2str(find(rms(VALS) == max(rms(VALS)))-100) ])    qtriplot('step 0.2')    qtriplot('signal 0 0.1 0.1 0.3 0.3')    qtriplot('mouse vertex');    qtriplot('elfile 64.el');%     qtriplot('marker thorax=vertex 0');    pause(0.1)    qtriplot('column 0')endfunction [VER,ITRI] = loadAMSGEOM()VER=[     1    46.50  -145.50   123.40    2    84.40  -145.50     0.00    3    99.40  -145.50   -73.30    4    50.60   -90.10   120.10    5    88.30   -90.10    64.80    6   106.40   -90.10     0.00    7   120.80   -90.10   -63.60    8   131.10   -90.10  -129.10    9   133.20   -90.10  -194.40   10    63.00   -44.90   121.20